parameters.jsCode:
const geminiResponse = $input.first().json;
const rawText = geminiResponse.candidates?.[0]?.content?.parts?.[0]?.text ?? '';
const cleaned = rawText.replace(/```json|```/g, '').trim();

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  parsed = {
    contact_name: null,
    company: null,
    summary: rawText,
    action_items: [],
    outcome: 'follow_up_needed',
    sentiment: 'neutral'
  };
}

const timestamp = new Date().toLocaleString('nb-NO', { timeZone: 'Europe/Oslo' });
const actionItemsText = parsed.action_items?.length > 0
  ? '\n\nAction items:\n' + parsed.action_items.map(a => `• ${a}`).join('\n')
  : '';

const noteBody = [
  `📞 Call summary — ${timestamp}`,
  '',
  parsed.summary,
  actionItemsText,
  '',
  `Outcome: ${parsed.outcome ?? 'unknown'} | Sentiment: ${parsed.sentiment ?? 'unknown'}`,
  parsed.company ? `Company: ${parsed.company}` : null,
].filter(Boolean).join('\n');

return [{
  json: {
    contact_name: parsed.contact_name,
    company: parsed.company,
    note_body: noteBody,
    outcome: parsed.outcome,
    sentiment: parsed.sentiment,
  }
}];

